noncompliant:
#include <algorithm>
#include <vector>

void func() {
    std::vector<int> data = {1, 2, 3, 4, 5};
    int multiplier = 10;

    // Noncompliant: capturing by copy when reference would be better
    std::transform(data.begin(), data.end(), data.begin(),
                   [multiplier](int x) { return x * multiplier; });
}

compliant:
#include <algorithm>
#include <vector>

void func() {
    std::vector<int> data = {1, 2, 3, 4, 5};
    int multiplier = 10;

    // Compliant: capturing by reference for local algorithm usage
    std::transform(data.begin(), data.end(), data.begin(),
                   [&multiplier](int x) { return x * multiplier; });
}
